  ('aboriginal-d0d1b9a2-moex-00068', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'essay', '請依中央政府普通公務單位會計制度之一致規定，就甲機關在110 年度
發生之下列交易事項，做正確會計分錄（請用四級會計科目完整作答，
不要簡併會計分錄）。（25分）
交易事項 應有之分錄
1. 甲機關為執行 108 年度奉准保留的
計畫，使用以前年度購買已配合計畫
辦理預算保留之剩餘材料
2. 甲機關為執行 109 年度奉准保留的
計畫，使用以前年度購買未配合計畫
辦理預算保留之剩餘材料
3. 審計機關於108年度終了後，剔除甲
機關某項支出，甲機關於110年度收
到繳款帳戶通知並辦理繳庫
4. 110年1月間行政院減列109年甲機
關撥付所屬 A 特別收入基金的支出
實現數，改列為歲出保留數
5. 某項機械設備尚未屆耐用年限，卻因
發生火災損毀，並收到保險理賠收入
繳庫', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00069', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '關於普通基金之敘述，下列何者正確？', '["普通基金主要採統收統支原則提供公共服務，故無須計算成本", "單位預算為普通基金預算，故兩者皆為獨立之財務及會計個體", "中央與地方政府構成一個普通基金", "普通基金歲入及歲出之間不具備一定的對價關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00070', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計觀念公報第2號規定，政府會計資訊之最高品質及其須具備之品質特性，分別為何？', '["決策有用性、時效性及可瞭解性", "跨期間公平性、時效性及可瞭解性", "決策有用性、攸關性及忠實表述", "跨期間公平性、攸關性及忠實表述"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00071', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第3號規定，甲機關將委辦費先行撥付受託者備用，年度終了未支用部分， 應認列為何項科目？', '["應收帳款", "存出保證金", "暫付款", "預付款"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00072', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第3號及中央政府普通公務單位會計制度之一致規定，有關政府補助支出之 敘述，下列何者正確？', '["公務機關對所管特別收入基金資本門之補助預算，應列為長期投資", "公務機關對民間團體之補助，於次年度收回補助結餘款應帳列於資產負債淨額", "對不同政府間或民間團體之補助，如未設定條件，應於撥款時認列支出", "資源提供者若可要求收回已支付之部分資源時，應列為資產負債淨額之減項"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00073', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第7號規定，有關負債準備、或有負債及或有資產之敘述，下列何者正確？', '["現時法定義務存在之可能性大於不可能性時，應即認列為負債準備", "政府設置特種基金之負 債準備、或有負債，係辦理社會保險所產生者，應以揭露方式辦理", "負債準備清償時，若因保 險契約幾乎確定可以獲得理賠款，應將其認列為資產及收入", "或有資產不予認列，但若其很有 可能流入資源時，應認列該項資產及收入"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00074', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第4號規定，土地、土地改良物、房屋建築及設備、雜項設備、租賃資產、 租賃權益改良、傳承資產、非消耗性收藏品，不予提列折舊者有幾項？', '["3項", "4項", "5項", "6項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00075', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第6號規定，公共債務主管機關於X1年6月30日發行新公債50億元，實 際售價 48 億元，折價 2 億元，並撥付予債務基金作為償付到期公債之還款金額。假設該新公債 於X1年12月31日應攤銷之折價數2,000萬元，債務基金如何處理？', '["不作分錄", "借：國庫應撥款數，貸：公債折價", "借：還本付息支出，貸：銀行存款", "借：未攤銷折價，貸：公債折價"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00076', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依政府會計準則公報第1號規定，下列何者非為政府財務報導要素？', '["資產", "餘絀", "收入", "支出"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL),
  ('aboriginal-d0d1b9a2-moex-00077', 'aboriginal-d0d1b9a2', 'aboriginal-d0d1b9a2-moex-113-fa8ff513', 'sub-aboriginal-d0d1b9a2-01', NULL, 'single_choice', '依中央政府普通公務單位會計制度之一致規定及政府會計準則公報第9號規定，有關公務機關預 算執行控制之會計處理，下列敘述何者正確？', '["應於發生契約責任時，按未來須支付金額，先作預算保留記錄", "有關預算控制科目之設置，係用以記載預算之成立、分配、執行及保留等", "歲出預算經核准轉入下年度繼續執行部分，不必作預算控制", "會計報告中應揭露預算及其實際執行結果之比較資訊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:04+00:00", "source_pdf_sha1": "d8bea15b0013", "answer_pdf_sha1": "6e84be962263", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "506", "s": "1306", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "會計"}'::jsonb, NULL)
